 *  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Reopen Tasks
//------------------------------------------------------------------------------------------------------------------------
// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column
//                                      In HTML, created widget to show comments data with gray background on even rows
//                                      In Server script, created widget; pull comments data into an array
//                                      In Client controller, created widget to show a Close button
//                                      Changes made in HTML, Server script and Client controller.
// 2.8.5 | 2023-07-17 | mmcc | DFCT0012086 - "Show All Responses" Hover over the "Close" button, should NOT display 
//                                       the Incorrect toot tip as "Cancel"
//                                      In HTML, update <button> tag's title to use cancelButtonText
//                                      Changes made in HTML.
// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal
//                                      In HTML, added use of sp-tinymce-editor, adjusted bottom padding style and
//                                       show buttons based on being able to write to a field per ACL;
//                                        If Page Additional options, JSON format does not include entry then default to form version.
//                                        If Page Additional options, JSON format does include "responseEditorControl": "directive"
//                                          then use non-form directive <sp-tinymce-editor>
//                                      In Server script, added _processInput() and _resetReord(); add use of TaskerTaskACLs();
//                                       removed _optCopy() and use _setDataDefaults() to set sys_id from input or options; 
//                                       added gs to open and close ()
//                                      In Client controller, added functions for non-form and form Cancel's and Submit's
//                                      Changes made in HTML, Server script and Client controller.
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added gs and table name var's
	var actionLogTableName = 'x_153465_discovert_discover_tasker_response';
	var taskTableName = 'x_153465_discovert_route_task_instance';

	main();

	function main() {
		if (input) {
			if (input.submit == true) {
				_processInput();

			} else {
				_setDataDefaults();
				_convertToBool(['isModal']);
				_buildMessages();
				_getTaskData();
			}
		}
	}

	// Use this function to get Messages that will be used in this widget
	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');

		data.closeButtonText = gs.getMessage('Tasker - Button - Close');

		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added Save
		data.submitButtonText = gs.getMessage('Tasker - Button - Save');
		data.submitButtonTitle = gs.getMessage('Tasker - Button - Save');
		data.updatedMsg = gs.getMessage("updated_uppercase");

	}

	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

	function _getTaskData() {
		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added _resetRecord()
		var record = _resetReord();

		data.list = [];

		if (data.sys_id == undefined) {
			return;
		} else {
			var grTableData = new GlideRecordSecure(data.table);

			data.assignedTo = {};

			// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added canWriteTable
			data.canWriteTable = false;

			data.name = {};
			data.number = {};
			data.state = {};

			if (grTableData.get(data.sys_id)) {

				// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added var to get ACLs
				var TaskACLs = new TaskerTaskACLs(grTableData);
				// data.canRead = grTableData.canRead();
				// data.canWrite = grTableData.canWrite();

				switch (data.table) {
					// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added var table name
					case taskTableName:
						data.isBadgeShown = true;

						data.assignedTo.displayValue = grTableData.getElement('assigned_to').getDisplayValue();
						data.assignedTo.label = grTableData.getElement('assigned_to').getLabel();

						data.name.displayValue = grTableData.getElement('short_description').getDisplayValue(50);
						data.name.label = grTableData.getElement('short_description').getLabel();

						data.number.displayValue = grTableData.getElement('number').getDisplayValue();
						data.number.label = grTableData.getElement('number').getLabel();

						data.state.displayValue = grTableData.getElement('state').getDisplayValue();
						data.state.label = grTableData.getElement('state').getLabel();

						// Build an array of Task data for ngRepeat
						if (grTableData.getElement('response').getDisplayValue().length > 0) {
							// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit comments; added canWriteField, name and _resetRecord()
							record.canWriteField = TaskACLs.setResponsePermissions();
							record.comments = grTableData.getElement('response').getDisplayValue();
							record.label = grTableData.getElement('response').getLabel();
							record.name = grTableData.getElement('response').getName();
							record.svg = 'ResponseComment16.svg';
							data.list.push(record);
							record =  _resetReord();
						}

						// Reviewer
						if (grTableData.getElement('comments_dt').getDisplayValue().length > 0) {
							// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit comments; added canWriteField, name and _resetRecord()
							record.canWriteField = TaskACLs.setReviewerCommentsPermissions();
							record.comments = grTableData.getElement('comments_dt').getDisplayValue();
							record.label = grTableData.getElement('comments_dt').getLabel();
							record.name = grTableData.getElement('comments_dt').getName();
							record.svg = 'View16.svg';
							data.list.push(record);
							record =  _resetReord();
						}

						if (grTableData.getElement('rework_comments').getDisplayValue().length > 0) {
							// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit comments; added canWriteField, name and _resetRecord()
							record.canWriteField = TaskACLs.setReworkCommentsPermissions();
							record.comments = grTableData.getElement('rework_comments').getDisplayValue();
							record.label = grTableData.getElement('rework_comments').getLabel();
							record.name = grTableData.getElement('rework_comments').getName();
							record.svg = 'Rework16.svg';
							data.list.push(record);
							record =  _resetReord();
						}

						if (grTableData.getElement('reopen_comments').getDisplayValue().length > 0) {
							// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; canWriteField defaults to false
							record.comments = grTableData.getElement('reopen_comments').getDisplayValue();
							record.label = grTableData.getElement('reopen_comments').getLabel();
							// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; added name and _resetRecord()
							record.name = grTableData.getElement('reopen_comments').getName();
							record.svg = 'Reopen16.svg';
							data.list.push(record);
							record =  _resetReord();
						}

						// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit comments; When the first true canWriteField is found exit loop
						data.canWriteTable = data.list.some(function(rec) {
							return rec.canWriteField;
						});

						break;
					// Action Log table
					case actionLogTableName:
						// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; Action Log will not need to show TinyMCE
						data.canWriteTable = false;
						data.isBadgeShown = false;

						data.assignedTo.displayValue = grTableData.getElement('u_responded_by').getDisplayValue();
						data.assignedTo.label = grTableData.getElement('u_responded_by').getLabel();

						data.name.displayValue = grTableData.getElement('u_task.short_description').getDisplayValue(50);
						data.name.label = grTableData.getElement('u_task.short_description').getLabel();

						data.number.displayValue = grTableData.getElement('u_task_number').getDisplayValue();
						data.number.label = grTableData.getElement('u_task_number').getLabel();

						data.state.displayValue = grTableData.getElement('u_action_taken').getDisplayValue();
						data.state.label = grTableData.getElement('u_action_taken').getLabel();


						var commentType = grTableData.getValue('u_comment_type');
						// in the Action Log table, always use the Response column
						switch(commentType){
							case 'comments_dt':
								// Reviewer
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'View16.svg';
								data.list.push(record);
								// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; added _resetRecord()
								record =  _resetReord();
								break;
							case 'reopen_comments':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'Reopen16.svg';
								data.list.push(record);
								// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; added _resetRecord()
								record =  _resetReord();
								break;
							case 'response':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'ResponseComment16.svg';
								data.list.push(record);
								// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; added _resetRecord()
								record =  _resetReord();
								break;
							case 'rework_comments':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'Rework16.svg';
								data.list.push(record);
								// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments; added _resetRecord()
								record =  _resetReord();
								break;
						}
						break;
					default:
						break;
				}
			}
		}
	}

	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; save comments
	function _processInput() {
		if (input.sys_id) {
			// Save edits
			var grSaveTask = new GlideRecordSecure(taskTableName);
			var needsUpdate = false;

			if (grSaveTask.get(input.sys_id)) {
				input.list.forEach(function(record) {
					if (record.canWriteField) {
						// put data into the table's column
						grSaveTask.setValue(record.name, record.comments);
						needsUpdate = true;
					}
				});

				if (needsUpdate) {
					new Task_uiAction().uiAction_Update(grSaveTask);
				}
			}
		}
	}

	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added _resetRecord()
	function _resetReord() {
		var record = {
			canWriteField: false,
			comments: '',
			label: '',
			name: '',
			svg: ''			
		};

		return record;
	}

	// Use this function to set defaults
	function _setDataDefaults() {
		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
		var responseEditorControl = (input || {}).responseEditorControl || (options || {}).responseEditorControl || 'form';

		data.isModal = (input || {}).isModal || (options || {}).isModal || false;

		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added submit and sys_id
		data.submit = false;
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id;

		data.table = (input || {}).table || (options || {}).table;

		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
		var viewForm = _setViewByTable(data.table);
		data.useTinyMCE = _setUseTinyMCE(responseEditorControl);
		data.f = $sp.getForm(data.table, data.sys_id, '', viewForm);
	}

	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
	function _setUseTinyMCE(editorControl) {
		var editorResult = false;

		if (editorControl == 'directive') {
			editorResult = true;
		} 

		return editorResult;
	}

	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
	function _setViewByTable(table) {
		var viewResult = '';

		if (table == taskTableName) {
			viewResult = 'task_all_comments';
		} else if (table == actionLogTableName) {
			viewResult = 'response_view';
		}

		return viewResult;
	}
})($sp, input, data, options, gs);
